module RefModule(  
    input wire clk,  
    input wire rst,  
    input wire enable,  
    input wire [1:0] ctrl,  
    output reg [1:0] gpio_out  
);  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            gpio_out <= 2'b00;  
        else if (enable) begin  
            gpio_out <= ctrl;  
        end  
    end  
endmodule
